    UINT presentation_count_ = 0;
    WMT::Object native_view_;
    WMT::MetalLayer layer_;
    Rc<Presenter> presenter_;
    HUDState hud_;
    Com<IDXGIOutput> target_;
    UINT frame_latency_ = 1;
    UINT source_width_ = 0;
