  struct ResourceAccessBarrierEntry {
    Com<ID3D12Resource> d3d_resource;
    Rc<Buffer> buffer;
    Rc<Texture> texture;
    UINT64 buffer_length = 0;
    UINT level = 0;
    UINT slice = 0;
    int access = 0;
    bool requires_cross_submit_wait = false;
  };

  struct ResourceAccessBarrierKey {
    uintptr_t object = 0;
    uintptr_t d3d_resource = 0;
    UINT level = 0;
    UINT slice = 0;
    bool texture = false;

    bool operator==(const ResourceAccessBarrierKey &other) const {
      return object == other.object && d3d_resource == other.d3d_resource &&
             level == other.level &&
             slice == other.slice && texture == other.texture;
    }
  };

  struct ResourceAccessBarrierKeyHash {
    size_t operator()(const ResourceAccessBarrierKey &key) const {
      size_t hash = std::hash<uintptr_t>{}(key.object);
      hash ^= (std::hash<uintptr_t>{}(key.d3d_resource) +
               0x9e3779b97f4a7c15ull + (hash << 6) + (hash >> 2));
      hash ^= (size_t(key.level) + 0x9e3779b97f4a7c15ull + (hash << 6) +
               (hash >> 2));
      hash ^= (size_t(key.slice) + 0x9e3779b97f4a7c15ull + (hash << 6) +
               (hash >> 2));
      hash ^= (size_t(key.texture) + 0x9e3779b97f4a7c15ull + (hash << 6) +
               (hash >> 2));
      return hash;
    }
  };

  struct ResourceAccessBarrierBatch {
    std::vector<ResourceAccessBarrierEntry> entries;
    std::unordered_map<ResourceAccessBarrierKey, size_t,
                       ResourceAccessBarrierKeyHash>
        entry_index;
    // Stable keys keep resource lookups valid while entries are swap-removed.
    std::unordered_map<ID3D12Resource *,
                       std::vector<ResourceAccessBarrierKey>>
        resource_entry_keys;
    bool needs_separator = false;
  };

  static constexpr size_t kResourceAccessBarrierLinearEntryLimit = 32;

  static ResourceAccessBarrierKey
  MakeResourceAccessBarrierKey(const ResourceAccessBarrierEntry &entry) {
    ResourceAccessBarrierKey key = {};
    key.d3d_resource =
        reinterpret_cast<uintptr_t>(entry.d3d_resource.ptr());
    if (entry.buffer) {
      key.object = reinterpret_cast<uintptr_t>(entry.buffer.ptr());
    } else {
      key.object = reinterpret_cast<uintptr_t>(entry.texture.ptr());
      key.level = entry.level;
      key.slice = entry.slice;
      key.texture = true;
    }
    return key;
  }

  static bool
  ResourceAccessBarrierEntriesMatch(const ResourceAccessBarrierEntry &lhs,
                                    const ResourceAccessBarrierEntry &rhs) {
    if (lhs.buffer || rhs.buffer)
      return lhs.d3d_resource.ptr() == rhs.d3d_resource.ptr() &&
             lhs.buffer.ptr() == rhs.buffer.ptr();
    return lhs.d3d_resource.ptr() == rhs.d3d_resource.ptr() &&
           lhs.texture.ptr() == rhs.texture.ptr() && lhs.level == rhs.level &&
           lhs.slice == rhs.slice;
  }

  static void
  MergeResourceAccessBarrierEntry(ResourceAccessBarrierEntry &dst,
                                  ResourceAccessBarrierEntry &&src) {
    dst.buffer_length = std::max(dst.buffer_length, src.buffer_length);
    dst.access |= src.access;
    dst.requires_cross_submit_wait = dst.requires_cross_submit_wait ||
                                     src.requires_cross_submit_wait;
  }

  static void
  RebuildResourceAccessBarrierIndex(ResourceAccessBarrierBatch &batch) {
    batch.entry_index.clear();
    batch.entry_index.reserve(batch.entries.size());
    batch.resource_entry_keys.clear();
    for (size_t i = 0; i < batch.entries.size(); i++) {
      auto key = MakeResourceAccessBarrierKey(batch.entries[i]);
      batch.entry_index.emplace(key, i);
      if (auto *resource = batch.entries[i].d3d_resource.ptr())
        batch.resource_entry_keys[resource].push_back(key);
    }
  }

